const productos=$('Parsear Input').first().json.productos||[];const apiKey=$vars.INTCOMEX_API_KEY;const allResults=[];
for(const p of productos){
  try{
    const resp=await $helpers.httpRequest({method:'GET',url:'https://iws.intcomex.com/api/catalog/search',headers:{Authorization:`Bearer ${apiKey}`,'Content-Type':'application/json'},qs:{q:p.searchQuery,country:'MX',limit:5}});
    const items=resp.items||resp.products||resp.data||[];
    for(const item of (Array.isArray(items)?items:[]).slice(0,3)){
      allResults.push({mayorista:'INTCOMEX',sku:item.sku||item.partNumber||'',skuFabricante:item.vendorPartNumber||'',descripcion:item.description||item.name||'',marca:item.brand||item.vendor||p.marca,precio:Number(item.price||item.unitPrice||0),moneda:item.currency||'MXN',existencia:Number(item.quantityAvailable||item.stock||0),disponible:(item.quantityAvailable||0)>0,imagenUrl:item.imageUrl||'',productoBuscado:p.searchQuery});
    }
  }catch(e){allResults.push({mayorista:'INTCOMEX',error:e.message,productoBuscado:p.searchQuery});}
}
return allResults.map(r=>({json:r}));
